     1→import { createStore } from 'zustand/vanilla';
     2→import { useStore } from 'zustand';
     3→
     4→/**
     5→ * Viewport state for canvas rendering.
     6→ * Uses Zustand vanilla store for direct subscription without React re-renders.
     7→ *
     8→ * Coordinate system:
     9→ * x_viewport = (t_unix - t_origin) * scale + offset
    10→ */
    11→export interface ViewportState {
    12→  /** Pixels per millisecond */
    13→  scale: number;
    14→  /** Viewport offset in pixels (virtual scroll position) */
    15→  offsetX: number;
    16→  offsetY: number;
    17→  /** Origin timestamp (start of timeline) */
    18→  originTime: number;
    19→  /** Viewport dimensions */
    20→  width: number;
    21→  height: number;
    22→  /** Current Level of Detail (0=heatmap, 1=bars, 2=capsules) */
    23→  lod: 0 | 1 | 2;
    24→}
    25→
    26→export interface ViewportActions {
    27→  setScale: (scale: number) => void;
    28→  setOffset: (x: number, y: number) => void;
    29→  pan: (deltaX: number, deltaY: number) => void;
    30→  zoom: (factor: number, centerX: number, centerY: number) => void;
    31→  setDimensions: (width: number, height: number) => void;
    32→  setLod: (lod: 0 | 1 | 2) => void;
    33→}
    34→
    35→const INITIAL_SCALE = 0.00001; // px/ms (approximately 36px per hour)
    36→const MIN_SCALE = 0.0000001; // Very zoomed out (years visible)
    37→const MAX_SCALE = 0.001; // Very zoomed in (seconds visible)
    38→
    39→/** LOD thresholds with hysteresis (px per hour) */
    40→const LOD_THRESHOLDS = {
    41→  heatmapToBarEnter: 0.1,
    42→  heatmapToBarExit: 0.15,
    43→  barToCapsuleEnter: 20,
    44→  barToCapsuleExit: 15,
    45→} as const;
    46→
    47→function calculateLod(scale: number, currentLod: 0 | 1 | 2): 0 | 1 | 2 {
    48→  const pxPerHour = scale * 3600000; // ms per hour
    49→
    50→  if (currentLod === 0) {
    51→    if (pxPerHour > LOD_THRESHOLDS.heatmapToBarExit) return 1;
    52→    return 0;
    53→  }
    54→
    55→  if (currentLod === 1) {
    56→    if (pxPerHour < LOD_THRESHOLDS.heatmapToBarEnter) return 0;
    57→    if (pxPerHour > LOD_THRESHOLDS.barToCapsuleEnter) return 2;
    58→    return 1;
    59→  }
    60→
    61→  // currentLod === 2
    62→  if (pxPerHour < LOD_THRESHOLDS.barToCapsuleExit) return 1;
    63→  return 2;
    64→}
